111:   // Cleanup function - automatically registered with afterEach
112:   const cleanup = async () => {
113:     // Clean up in correct order to respect foreign key constraints
114:     await prisma.userFeatures.deleteMany({
115:       where: { userId: user.id },
116:     });
117:     await prisma.teamFeatures.deleteMany({
118:       where: { teamId: { in: [team.id, team2.id, org.id] } },
119:     });
120:     await prisma.feature.deleteMany({
121:       where: { slug: { in: createdFeatures } },
122:     });
123:     await prisma.membership.deleteMany({
124:       where: { userId: user.id },
125:     });
126:     await prisma.team.deleteMany({
127:       where: { id: { in: [team.id, team2.id] } },
128:     });
129:     await prisma.team.deleteMany({
130:       where: { id: org.id },
131:     });
132:     await prisma.user.delete({
133:       where: { id: user.id },
134:     });
135:   };
136: 
137:   // Register cleanup to run automatically after each test
138:   cleanupFunctions.push(cleanup);
139: 
140:   return {
141:     user,
142:     org,
143:     team,
144:     team2,
145:     featuresRepository,
146:     service,
147:     createdFeatures,
148:     setupFeature,
149:   };
150: }
