20: /**
21:  * Computes the effective enabled state based on global, org, teams, and user settings.
22:  *
23:  * The logic depends on the policy:
24:  *
25:  * **Permissive policy (default):**
26:  * - User opt-in can activate the feature
27:  * - Any explicit enable above is sufficient
28:  * - Disables only win if ALL teams disable
29:  *
30:  * **Strict policy:**
31:  * - User opt-in alone is NOT enough - requires explicit enable from org/team
32:  * - ANY explicit disable blocks
33:  *
34:  * Returns both the enabled state and the reason for that state.
35:  */
36: export function computeEffectiveStateAcrossTeams({
37:   globalEnabled,
38:   orgState,
39:   teamStates,
40:   userState,
41:   policy,
42: }: {
43:   /**
44:    * Acts as a global kill switch. When false, the feature is disabled for everyone.
45:    * When true, the feature is NOT necessarily enabled - enablement still depends on
46:    * the org, team, and user state hierarchy.
47:    */
48:   globalEnabled: boolean;
49:   orgState: FeatureState;
50:   teamStates: FeatureState[];
51:   userState: FeatureState;
52:   /**
53:    * Policy that determines how feature opt-in states are evaluated.
54:    */
55:   policy: OptInFeaturePolicy;
56: }): EffectiveStateResult {
57:   // Derive all conditions upfront
58:   const orgEnabled = orgState === "enabled";
59:   const orgDisabled = orgState === "disabled";
60:   const anyTeamEnabled = teamStates.some((s) => s === "enabled");
61:   const anyTeamDisabled = teamStates.some((s) => s === "disabled");
62:   const allTeamsDisabled = teamStates.length > 0 && teamStates.every((s) => s === "disabled");
63:   const userEnabled = userState === "enabled";
64:   const userDisabled = userState === "disabled";
65: 
66:   // Explicit enablement exists above user level
67:   const hasExplicitEnablementAboveUser = orgEnabled || anyTeamEnabled;
68: 
69:   // Check conditions in order of precedence and return with reason
70:   if (!globalEnabled) {
71:     return { enabled: false, reason: "feature_global_disabled" };
72:   }
73: 
74:   if (orgDisabled) {
75:     return { enabled: false, reason: "feature_org_disabled" };
76:   }
77: 
78:   if (policy === "strict") {
79:     // Strict policy: ANY explicit disable blocks
80:     if (anyTeamDisabled) {
81:       return { enabled: false, reason: "feature_any_team_disabled" };
82:     }
83: 
84:     // Strict policy: User opt-in alone is NOT enough - requires explicit enable from org/team
85:     if (userEnabled && !hasExplicitEnablementAboveUser) {
86:       return { enabled: false, reason: "feature_user_only_not_allowed" };
87:     }
88: 
89:     if (userDisabled) {
90:       return { enabled: false, reason: "feature_user_disabled" };
91:     }
92: 
93:     if (!hasExplicitEnablementAboveUser) {
94:       return { enabled: false, reason: "feature_no_explicit_enablement" };
95:     }
96: 
97:     return { enabled: true, reason: "feature_enabled" };
98:   }
99: 
100:   // Permissive policy (default): disables only win if ALL teams disable
101:   if (allTeamsDisabled) {
102:     return { enabled: false, reason: "feature_all_teams_disabled" };
103:   }
104: 
105:   if (userDisabled) {
106:     return { enabled: false, reason: "feature_user_disabled" };
107:   }
108: 
109:   if (!userEnabled && !hasExplicitEnablementAboveUser) {
110:     return { enabled: false, reason: "feature_no_explicit_enablement" };
111:   }
112: 
113:   return { enabled: true, reason: "feature_enabled" };
114: }
